function findTwoIndexes(arr, target) {
    const indexDict = {};
    for (let i = 0; i < arr.length; i++) {
        const diff = target - arr[i];
        if (indexDict.hasOwnProperty(diff)) {
            return [indexDict[diff], i];
        }
        indexDict[arr[i]] = i;
    }
    return [];
}

const inputArr = [2, 7, 11, 15];
const target = 9;
const indexes = findTwoIndexes(inputArr, target);
console.log(indexes);

