from heapq import heappop, heappush

class MinHeap:
    def __init__(self):
        self.heap = list()

    def push(self, k):
        heappush(self.heap, k)

    def decreaseKey(self, i, new_val):
        self.heap[i] = new_val
        while i != 0 and self.heap[int((i - 1) / 2)] > self.heap[i]:
            self.heap[i], self.heap[int((i - 1) / 2)] = self.heap[int((i - 1) / 2)], self.heap[i]
            i = int((i - 1) / 2)

    def pop(self):
        if self.heap:
            self.heap[0] = self.heap[len(self.heap) - 1]
            self.heap.pop()
            self.minHeapify(0)
        else:
            return None

    def minHeapify(self, i):
        l = 2 * i + 1
        r = 2 * i + 2
        smallest = i
        if l < len(self.heap) and self.heap[i] > self.heap[l]:
            smallest = l
        if r < len(self.heap) and self.heap[smallest] > self.heap[r]:
