        {
            using var connection = new SQLiteConnection(ConnectionString);
            connection.Open();

            using var command = new SQLiteCommand(connection);
            command.CommandText = "SELECT * FROM accounts WHERE name = @name";
            command.Parameters.AddWithValue("@name", name);

            using var reader = command.ExecuteReader();
            if (!reader.Read())
            {
                return null;
            }

            return new Account
            {
                AccountNumber = reader.GetInt32(0),
                Name = reader.GetString(1),
                Balance = reader.GetDecimal(2)
            };
        }

        public static void Deposit(Account account, decimal amount)
        {
            using var connection = new SQLiteConnection(ConnectionString);
            connection.Open();

            using var command = new SQLiteCommand(connection);
            command.CommandText = @"UPDATE accounts 
                                    SET balance = balance + @amount 
                                    WHERE account_number = @accountNumber";
            command.Parameters.AddWithValue("@amount", amount);
            command.Parameters.AddWithValue("@accountNumber", account.AccountNumber);
            command.ExecuteNonQuery();
        }

        public static bool Withdraw(Account account, decimal amount)
        {
            if (account.Balance < amount)
            {
                return false;
            }

            using var connection = new SQLiteConnection(ConnectionString);
            connection.Open();

            using var command = new SQLiteCommand(connection);
            command.CommandText = @"UPDATE accounts 
                                    SET balance = balance - @amount 
                                    WHERE account_number = @accountNumber";
            command.Parameters.AddWithValue("@amount", amount);
            command.Parameters.AddWithValue("@accountNumber", account.AccountNumber);
            command.ExecuteNonQuery();

            return true;
        }
    }
