```
import (
    "math/rand"
    "strings"
    "time"
)
func isWeightTargetMet(word string, weights string, target int) bool {
    // Shuffle the weights string using Fisher-Yates algorithm
    rand.Seed(time.Now().UnixNano())
    weightsArr := strings.Split(weights, "")
    for i := len(weightsArr) - 1; i > 0; i-- {
        j := rand.Intn(i + 1)
        weightsArr[i], weightsArr[j] = weightsArr[j], weightsArr[i]
    }
    shuffledWeights := strings.Join(weightsArr, "")
    // Compute the weight sum of the word using the shuffled weights
    alphabet := "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
    weightSum := 0
    for i := 0; i < len(word); i++ {
        letter := string(word[i])
        letterWeight := strings.IndexByte(alphabet, letter[0]) + 1
        shuffledLetter := string(shuffledWeights[letterWeight-1])
        shuffledLetterWeight := strings.IndexByte(alphabet, shuffledLetter[0]) + 1
        weightSum += shuffledLetterWeight
    }
    return weightSum == target
}
```
This code shuffles the weights string using the Fisher-Yates algorithm before computing the weight sum of the word using the shuffled weights. It also uses the same algorithm to shuffle the weights string each time the function is called, making the puzzle even more challenging.

