#include <iostream>

class Stack {
private:
    int* arr;
    int capacity;
    int top;

public:
    // Constructor to initialize stack with given size
    Stack(int size) {
        arr = new int[size];
        capacity = size;
        top = -1;
    }

    // Destructor to clean up dynamic array memory
    ~Stack() {
        delete[] arr;
    }

    // Push operation to add an element to the stack
    void push(int value) {
        if (isFull()) {
            std::cout << "Stack Overflow" << std::endl;
            return;
        }
        arr[++top] = value;
    }

    // Pop operation to remove and return the top element from the stack
    int pop() {
        if (isEmpty()) {
            std::cout << "Stack Underflow" << std::endl;
            return -1;
        }
        return arr[top--];
    }

    // Peek operation to return the top element without removing it
    int peek() const {
        if (isEmpty()) {
            std::cout << "Stack is empty" << std::endl;
            return -1;
        }
        return arr[top];
    }

    // Check if the stack is empty
    bool isEmpty() const {
        return top == -1;
    }

    // Check if the stack is full
    bool isFull() const {
        return top == capacity - 1;
    }

    // Get the current size of the stack
    int size() const {
        return top + 1;
    }
};

int main() {
    Stack stack(5);

    stack.push(1);
    stack.push(2);
    stack.push(3);
    stack.push(4);
    stack.push(5);

    std::cout << "Top element is: " << stack.peek() << std::endl;
    std::cout << "Stack size is: " << stack.size() << std::endl;

    stack.pop();
    stack.pop();

    std::cout << "Top element is: " << stack.peek() << std::endl;
    std::cout << "Stack size is: " << stack.size() << std::endl;

    return 0;
}

