    paceSecKm := timeSec / distanceKm

    // convert pace from seconds per kilometer to minutes per kilometer
    paceMinKm := paceSecKm / 60.0

    // round pace to nearest second
    paceMinKmRounded := math.Round(paceMinKm*60) / 60

    // output distance in miles and kilometers and pace in minutes per kilometer
    fmt.Printf("Distance: %.2f miles = %.2f kilometers\n", distance, distanceKm)
