def digit_operations_recursive(number: int, operation: str) -> int:
    def sum_digits(n: int) -> int:
        if n == 0:
            return 0
        return n % 10 + sum_digits(n // 10)

    def product_digits(n: int) -> int:
        if n == 0:
            return 1
        digit = n % 10
        return 1 if digit == 0 else digit * product_digits(n // 10)

    if operation == 'sum':
        return sum_digits(number)
    elif operation == 'product':
        return product_digits(number)
    else:
        raise ValueError("Invalid operation. Only 'sum' and 'product' are supported.")
