def generate_fibonacci_sequence(n):
    # Check if the input is valid
    if n <= 0:
        return []
    elif n == 1:
        return [0]
    elif n == 2:
        return [0, 1]

    # Initialize the sequence with first two terms
    fibonacci_sequence = [0, 1]

