def is_prime(num):
    if num < 2:
        return False
    for i in range(2, int(num ** 0.5) + 1):
        if num % i == 0:
            return False
    return True

def fibonacci(num):
    if num == 0:
        return 0
    elif num == 1:
        return 1
    else:
        return fibonacci(num-1) + fibonacci(num-2)

def sum_primes(start, end):
    if not isinstance(start, int) or not isinstance(end, int):
        return "Invalid input: Both start and end must be integers."
    if start < 0 or end < 0:
        return "Invalid input: Both start and end must be positive integers."
    if start > end:
        return "Invalid input: The starting point must be less than or equal to the ending point."

    prime_sum = 0
    for num in range(start, end+1):
        if is_prime(num):
            prime_sum += num
    return fibonacci(prime_sum)
```

